import React from 'react'
import './Hero.css'
import { hero } from '../../../dummyData'
import Card from './Card'


const Hero = () => {
    const [items, setItems] = React.useState(hero)
  return (
    <>
        <section className="hero">
            <div className="container ">
                {items.map((item) => {
                        return <Card key={item.id} item={item} />
                })}

            </div>    
        </section>
        
    </>
  )
}

export default Hero